if (value is PackageChannelNames.Stable or PackageChannelNames.Staging or PackageChannelNames.Daily or PackageChannelNames.Local)
        {
            return true;
        }

foreach (var pathHit in context.PathHits)
        {
            yield return new InstallationDiscoveryCandidate(pathHit.OriginalPath, "$PATH", pathHit.CanonicalPath);
        }

if (!anyMatch)
        {
            context.Logger.LogDebug(
                "Discovery: dotnet-tool store '{ToolStore}' exists but contains no '{BinaryName}' binary — not classifying as a real install.",
                toolStore, context.AspireBinaryName);
        }

foreach (var candidate in PathLookupHelper.FindAllFullPathsFromPath("aspire"))
        {
            var canonical = CliPathHelper.ResolveSymlinkToFullPath(candidate, logger);
            if (!string.IsNullOrEmpty(canonical))
            {
                yield return new InstallationPathHit(candidate, canonical);
            }
        }

foreach (var source in _candidateSources)
        {
            foreach (var candidate in source.GetCandidates(context))
            {
                yield return candidate;
            }
        }

try
        {
            canonicalProcessPath = Path.GetFullPath(processPath);
        }
        catch (Exception ex) when (ex is ArgumentException or PathTooLongException or NotSupportedException)
        {
            return false;
        }

if (string.IsNullOrEmpty(versionLine))
        {
            return new PeerProbeResult.Failed(DescribePrimaryFailure(primary, alsoTriedVersion: true));
        }

foreach (var scanner in scanners)
        {
            await scanner.ScanAsync(context, cancellationToken);
        }

if (manifest is null)
        {
            throw new InvalidOperationException("Aspire skills bundle manifest is empty or invalid.");
        }

if (manifestSkill is null)
        {
            throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Aspire skills bundle does not contain skill '{0}'.", skill.Name));
        }

if (string.IsNullOrWhiteSpace(manifest.Version))
        {
            throw new InvalidOperationException("Aspire skills bundle manifest must specify a version.");
        }

if (!skipCompatibilityCheck)
        {
            ValidateCompatibility(manifest.Supports, currentCliVersion, currentSdkVersion);
        }

if (skills is not { Length: > 0 })
        {
            throw new InvalidOperationException("Aspire skills bundle manifest must contain at least one skill.");
        }

if (!string.Equals(expectedHash, actualHash, StringComparison.OrdinalIgnoreCase))
        {
            throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Aspire skills bundle file '{0}' in skill '{1}' failed SHA-256 verification.", relativePath, skillName));
        }

if (string.IsNullOrWhiteSpace(description))
        {
            throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Aspire skills bundle skill '{0}' must define a frontmatter description in SKILL.md.", skillName));
        }

foreach (var excludedPath in skill.InstallExcludedRelativePaths ?? [])
        {
            var normalizedExcludedPath = NormalizeRelativePath(excludedPath);
            if (PathMatchesOrIsUnder(relativePath, normalizedExcludedPath))
            {
                return false;
            }
        }

if (string.Equals(relativePath, excludedPath, StringComparison.Ordinal))
        {
            return true;
        }

if (string.IsNullOrWhiteSpace(relativePath))
        {
            throw new InvalidOperationException("Aspire skills bundle contains an empty relative path.");
        }

if (supports is null)
        {
            throw new InvalidOperationException("Aspire skills bundle manifest must specify supported Aspire versions.");
        }

if (string.IsNullOrWhiteSpace(supports.AspireCli))
        {
            throw new InvalidOperationException("Aspire skills bundle manifest must specify supports.aspireCli.");
        }

if (comparators.Length == 0)
        {
            throw new InvalidOperationException("Aspire skills bundle contains an empty version range.");
        }

if (!SemVersion.TryParse(version, SemVersionStyles.Any, out var parsedVersion))
        {
            throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Aspire skills bundle contains an invalid version value '{0}'.", version));
        }

if (cachedBundle is not null)
        {
            CleanupStaleCacheEntries(cacheRoot, effectiveVersion);
            return AspireSkillsInstallResult.Installed(cachedBundle);
        }

if (embeddedResult.Status == AcquisitionStatus.Installed)
        {
            CleanupStaleCacheEntries(cacheRoot, effectiveVersion);
            return AspireSkillsInstallResult.Installed(embeddedResult.Bundle!);
        }

if (metadata is null)
        {
            logger.LogDebug("No embedded Aspire skills bundle metadata is available.");
            return AcquisitionResult.Unavailable();
        }

if (ValidateEmbeddedMetadata(metadata) is { } metadataError)
        {
            return AcquisitionResult.Failed(string.Format(
                CultureInfo.CurrentCulture,
                AgentCommandStrings.AspireSkillsInstaller_InvalidMetadata,
                metadataError));
        }

if (string.IsNullOrWhiteSpace(metadata.Version))
        {
            return AgentCommandStrings.AspireSkillsInstaller_MissingMetadataVersion;
        }

if (!string.Equals(metadata.Repository, GitHubRepository, StringComparison.OrdinalIgnoreCase))
        {
            return string.Format(
                CultureInfo.CurrentCulture,
                AgentCommandStrings.AspireSkillsInstaller_MetadataRepositoryMismatch,
                metadata.Repository,
                GitHubRepository);
        }

if (string.IsNullOrWhiteSpace(metadata.AssetName))
        {
            return AgentCommandStrings.AspireSkillsInstaller_MissingMetadataAssetName;
        }

foreach (var assetName in GetGitHubReleaseAssetNameCandidates(version))
        {
            var asset = release.Assets.FirstOrDefault(asset => string.Equals(asset.Name, assetName, StringComparison.OrdinalIgnoreCase));
            if (asset is not null)
            {
                return asset;
            }
        }
